mapper.select:
SELECT a.state, d.`label` AS 'states', a.create_time AS 'createTime', b.id AS 'id', b.channel, b.nickname, b.country, b.contact, b.avg_play_count AS 'avgPlayCount', b.score_level AS 'scoreLevel', b.`is_match` AS 'isMatch', d1.`label` AS 'isMatchs' FROM `a_hot` a LEFT JOIN `a_hot_basic` b ON b.`hot_id` = a.`id` AND b.`del_flag` = 0 LEFT JOIN `a_hot_coop` c ON c.`hotb_id` = b.`id` AND c.`del_flag` = 0 LEFT JOIN `a_hot_coop_product` c1 ON c1.`coop_id` = c.`id` AND c1.`del_flag` = 0 LEFT JOIN `sys_dict` d ON d.`value` = a.`state` AND d.`type` = 'hot_coop_state' AND d.`del_flag` = 0 LEFT JOIN `sys_dict` d1 ON d1.`value` = b.`is_match` AND d1.`type` = 'is_match' AND d1.`del_flag` = 0
AND b.`country` LIKE CONCAT('%',#{country},'%')
AND b.`hot_level` LIKE CONCAT('%',#{hotLevel},'%')
AND b.`hot_type` LIKE CONCAT('%',#{hotType},'%')
AND b.`channel` = #{channel}
AND b.`hots_id` LIKE CONCAT('%',#{hotsId},'%')
AND b.`is_match` = #{isMatch}
AND a.`state` = #{state}
AND c1.`product_name` LIKE CONCAT('%',#{productName},'%')
AND c1.`coop_fee` <= #{coopFee}
GROUP BY b.`id` ORDER BY a.create_time DESC
